('curated','Serious Eats','https://www.seriouseats.com/old-fashioned-recipe',
 'Old Fashioned',
 'Bourbon or rye, a sugar cube, Angostura bitters, and an orange peel. The original cocktail — unchanged for 200 years because it cannot be improved.',
 'https://images.unsplash.com/photo-1527661591914-5b67fd703b82?w=800&q=80',
 'American',ARRAY['drink','cocktail'],ARRAY[]::text[],
 '[{"name":"bourbon or rye whiskey","amount":60,"unit":"ml"},{"name":"sugar cube","amount":1,"unit":"whole"},{"name":"Angostura bitters","amount":2,"unit":"dashes"},{"name":"orange peel","amount":1,"unit":"strip"},{"name":"ice","amount":1,"unit":"large cube"}]'::jsonb,
 ARRAY['Place sugar cube in a rocks glass. Saturate with bitters and a splash of water.','Muddle until sugar dissolves.','Add ice cube.','Pour whiskey over ice.','Stir 20 times.','Express orange peel over the glass, run around the rim, drop in.'],
 3,0,1,160,0,6,0,0,6,5),

('curated','NYT Cooking','https://cooking.nytimes.com/recipes/1021671-daiquiri',
 'Classic Daiquiri',
 'Two parts rum, one part fresh lime, three-quarter parts simple syrup. The most abused cocktail in the world, and also the most perfect when made correctly.',
 'https://images.unsplash.com/photo-1470337458703-46ad1756a187?w=800&q=80',
 'Cuban',ARRAY['drink','cocktail'],ARRAY['vegan','dairy-free'],
 '[{"name":"white rum","amount":60,"unit":"ml"},{"name":"fresh lime juice","amount":30,"unit":"ml"},{"name":"simple syrup","amount":22,"unit":"ml"},{"name":"ice","amount":1,"unit":"cup"}]'::jsonb,
 ARRAY['Add rum, lime juice, and simple syrup to a shaker.','Fill with ice.','Shake hard for 15 seconds.','Double-strain into a chilled coupe glass.','Garnish with a lime wheel if desired.'],
 3,0,1,175,0,12,0,0,10,5),

('curated','Bon Appétit','https://www.bonappetit.com/recipe/classic-mojito',
 'Classic Mojito',
 'White rum, fresh mint, lime, sugar, soda. Cuba''s most famous export — bright, herbaceous, and dangerously easy to drink.',
 'https://images.unsplash.com/photo-1551538827-9c037cb4f32a?w=800&q=80',
 'Cuban',ARRAY['drink','cocktail'],ARRAY['vegan','dairy-free'],
 '[{"name":"white rum","amount":60,"unit":"ml"},{"name":"fresh mint leaves","amount":10,"unit":"leaves"},{"name":"lime","amount":1,"unit":"whole"},{"name":"sugar syrup","amount":22,"unit":"ml"},{"name":"soda water","amount":90,"unit":"ml"},{"name":"crushed ice","amount":1,"unit":"cup"}]'::jsonb,
 ARRAY['Muddle mint with sugar syrup in a highball glass — gently, just to bruise, not shred.','Cut lime into wedges, squeeze all juice in, drop wedges.','Fill glass with crushed ice.','Pour rum over ice.','Top with soda water.','Stir briefly. Garnish with mint sprig.'],
 5,0,1,195,0,16,0,0,12,10),

('curated','Serious Eats','https://www.seriouseats.com/whiskey-sour-recipe',
 'Whiskey Sour',
 'Bourbon, fresh lemon juice, simple syrup, and — the controversial part — an egg white for that silky foam. One of the essential five.',
 'https://images.unsplash.com/photo-1516535794938-6063878f08cc?w=800&q=80',
 'American',ARRAY['drink','cocktail'],ARRAY[]::text[],
 '[{"name":"bourbon","amount":60,"unit":"ml"},{"name":"fresh lemon juice","amount":30,"unit":"ml"},{"name":"simple syrup","amount":22,"unit":"ml"},{"name":"egg white","amount":1,"unit":"whole"},{"name":"Angostura bitters","amount":2,"unit":"dashes"},{"name":"ice","amount":1,"unit":"cup"}]'::jsonb,
 ARRAY['Combine bourbon, lemon juice, syrup, and egg white in a shaker (no ice).','Dry-shake vigorously for 15 seconds to emulsify the egg white.','Add ice and shake again for 15 seconds.','Strain into a rocks glass over ice, or into a coupe.','Add bitters dashes on the foam for garnish.'],
 5,0,1,185,3,14,1,0,12,20),

('curated','NYT Cooking','https://cooking.nytimes.com/recipes/1014697-manhattan',
